func NewTrustCommand(deps TrustDeps) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "trust",
		Short: "Manage the two-tier trust store",
		Long: "Manage the committed project pin (trusted_sha in .agent-sync.yaml) " +
			"and the per-user trust history (trust.jsonl).",
		SilenceUsage:  true,
		SilenceErrors: true,
