	canonical, _, head := makeUpdateRepo(t)
	ws := writeUpdateWS(t, canonical, head, "main")
	before := readManifest(t, ws)

	out, errOut, err := runUpdateCmd(t, ws, "", "--non-interactive")
	if err != nil {
